const express = require('express');
const mongoose = require('mongoose');
const app = express();
app.use(express.json());

const queryBuilder = async (Model, filters = {}, projection = {}, sort = {}) => {
    try {
        const results = await Model.find(filters, projection).sort(sort).exec();
        return results;
    } catch (error) {
        throw new Error(error);
    }
};

// Example model
const User = mongoose.model('User', new mongoose.Schema({
    name: String,
    age: Number,
    password: String,
    createdAt: { type: Date, default: Date.now }
}));

app.get('/api/users', async (req, res) => {
    const filters = req.query.filters ? JSON.parse(req.query.filters) : {};
    const projection = req.query.projection ? JSON.parse(req.query.projection) : {};
    const sort = req.query.sort ? JSON.parse(req.query.sort) : {};
    
    try {
        const users = await queryBuilder(User, filters, projection, sort);
        res.json(users);
    } catch (error) {
        res.status(500).send(error.message);
    }
});

